在RimWorld:环世界的源代码中，icosahedronGenerator.GenerateIcosahedron是用于生成一个icosahedron（二十面体）的主要方法。它的具体实现如下：

```
public static IcosahedronMesh GenerateIcosahedron(float radius, int subdivisions)
{
    float subSize = Mathf.PI / subdivisions;
    List<Vector3> vertices = new List<Vector3>(subdivisions * (subdivisions + 1) + 2);
    for (int i = 0; i <= subdivisions; i++)
    {
        float lat = Mathf.PI / 2 - subSize * i;
        float r = Mathf.Cos(lat) * radius;
        float y = Mathf.Sin(lat) * radius;
        for (int j = 0; j < subdivisions * 6; j++)
        {
            float lon = Mathf.PI / 180f * 60f * j;
            vertices.Add(new Vector3(Mathf.Cos(lon) * r, y, Mathf.Sin(lon) * r));
        }
    }
    vertices.Add(Vector3.up * radius);
    vertices.Add(Vector3.down * radius);

    List<TriangleIndices> indices = new List<TriangleIndices>(subdivisions * subdivisions * 20 + 20);
    for (int i = 0; i < subdivisions; i++)
    {
        for (int j = 0; j < subdivisions * 5; j++)
        {
            int row1 = i * (subdivisions * 6);
            int row2 = (i + 1) * (subdivisions * 6);
            int nextRow1 = (i < subdivisions - 1 ? row2 : subdivisions * 6);
            int nextRow2 = (i < subdivisions - 1 ? row1 + subdivisions * 6 : vertices.Count - 2);
            int i1 = row1 + (j % (subdivisions * 6));
            int i2 = nextRow1 + (j % (subdivisions * 6));
            int i3 = nextRow2 + (j % (subdivisions * 6));
            indices.Add(new TriangleIndices(i1, i2, i3));
            indices.Add(new TriangleIndices(i1, i3, i2));
        }
    }
    // construct mesh object
    var mesh = new IcosahedronMesh(vertices.ToArray(), indices.ToArray());
    mesh.InitCorners();
    mesh.Subdivide(subdivisions);
    mesh.InitFinal();
    mesh.radius = radius;
    return mesh;
}
```

该方法会基于指定的半径（radius）和细分次数（subdivisions），生成一个球体网格模型。该模型采用了表面三角剖分（triangulation）算法，将球面表面离散成多个三角面片进行渲染。球面节点数和三角面片数量随分辨率（subdivisions）的增加而增加，从而使球面网格变得更加细腻和真实。该方法会返回一个IcosahedronMesh对象，该对象封装了具体的网格数据。

在游戏中，生成的icosahedron（球体网格）将被用于渲染世界地图，同时也是生成地形、生物群落等自然元素的基础。

在RimWorld:环世界的源代码中，WorldGrid类是用来存储和管理整个游戏世界网格的类，其中包括了世界地图上每一个瓦块（tile）的信息。而worldGrid.tilesCount属性是记录了整个世界地图上一共有多少个瓦块的属性值。

具体来说，tilesCount的值是在WorldGrid的构造函数中通过计算得出的。在该构造函数中，worldGrid首先生成了一个关于游戏地图瓦块数量的数组，然后通过全局的World类中的StaticConstructorOnStartup函数获取游戏地图的实际长宽（size）。

接着，在length和height的循环中，通过坐标计算向数组中添加该坐标位置处的次序（序号），从而最终得出tilesCount的值，代码如下所示：

```
int num = 0;
for (int i = 0; i < length; i++)
{
    for (int j = 0; j < height; j++)
    {
        worldGrid.tileIDToNeighborsOffsets[num] = new int[10];
        worldGrid.tileIDToNeighborsValues[num] = new int[10];
        worldGrid.tiles[num] = new Tile();

        if (!Find.World.genSettings.planetCoverage.IsZero && !Find.World.genSettings.isRandom)
        {
            float num2 = Mathf.Max((float)(worldGrid.allTiles[num].elevation - -6f) / 16f, 0f);
            num2 = Mathf.Pow(num2, 2f);
            num2 *= Find.World.genSettings.planetCoverage * 2f;
            if (worldGrid.allTiles[num].biome.DrawMaterial.shader != ShaderDatabase.WorldOcean)
            {
                worldGrid.allTiles[num].biome = (BiomeDef)worldGrid.allTiles[num].biome.MostSimilarBiomeFor(worldGrid.allTiles[num]);
                num2 *= worldGrid.allTiles[num].biome.settlementSelectionWeight;
            }
            worldGrid.allTiles[num].settlementSelectionWeight = num2;
        }
        worldGrid.allTiles[num].lakeID = -1;
        worldGrid.allTiles[num].hilliness = Hilliness.Flat;
        worldGrid.allTiles[num].biome = BiomeDefOf.Ocean;
        worldGrid.allTiles[num].temperature = 0f;
        worldGrid.allTiles[num].rainfall = 0f;
        worldGrid.allTiles[num].pathCostCalculated = new int[Find.WorldReachability.NumWorldObjects];
        worldGrid.allTiles[num].waterCovered = true;
        worldGrid.allTiles[num].potentialRoads = new int[2];
        worldGrid.allTiles[num].potentialRivers = new int[2];
        worldGrid.allTiles[num].rivers = new List<int>();
        worldGrid.allTiles[num].neighbors = new Tile[9];
        worldGrid.allTiles[num].neighborID = new int[9];
        for (int k = 0; k < 9; k++)
        {
            worldGrid.allTiles[num].neighborID[k] = -1;
        }
        if (i == 0 || j == 0 || i == length - 1 || j == height - 1)
        {
            entireEdgeTiles[num] = true;
        }
        worldGrid.allTiles[num].id = num;
        worldGrid.allTiles[num].globalID = World.genWorldIDCounter;
        tilesArray[i, j] = num;
        num++;
    }
}
tilesCount = num;
```

因此，worldGrid.tilesCount具体的数值取决于当前游戏地图的大小，它将在世界网格（WorldGrid）生成时动态生成。

