```
int num = 0;
for (int i = 0; i < length; i++) //循环迭代地图的长度
{
    for (int j = 0; j < height; j++) //循环迭代地图的宽度
    {   
        //初始化Tiles数组中的一个元素（Tile），Tile 存储了该瓦块所拥有的信息，比如区域、山丘、湖泊等等。
        worldGrid.tileIDToNeighborsOffsets[num] = new int[10];
        worldGrid.tileIDToNeighborsValues[num] = new int[10];
        worldGrid.tiles[num] = new Tile();

        if (!Find.World.genSettings.planetCoverage.IsZero && !Find.World.genSettings.isRandom)//如果不是亚克力球世界
        {
            //根据海拔高度计算利用率，计算Pathfinder在由世界网格（WorldGrid）渲染的世界地图上的行走代价（路径长度和）和建筑物评估代价。

            float num2 = Mathf.Max((float)(worldGrid.allTiles[num].elevation - -6f) / 16f, 0f);
            num2 = Mathf.Pow(num2, 2f);
            num2 *= Find.World.genSettings.planetCoverage * 2f;
            if (worldGrid.allTiles[num].biome.DrawMaterial.shader != ShaderDatabase.WorldOcean)
            {
                worldGrid.allTiles[num].biome = (BiomeDef)worldGrid.allTiles[num].biome.MostSimilarBiomeFor(worldGrid.allTiles[num]);
                num2 *= worldGrid.allTiles[num].biome.settlementSelectionWeight;
            }
            worldGrid.allTiles[num].settlementSelectionWeight = num2;
        }

        //初始化瓦片的一些属性。
        worldGrid.allTiles[num].lakeID = -1;
        worldGrid.allTiles[num].hilliness = Hilliness.Flat;
        worldGrid.allTiles[num].biome = BiomeDefOf.Ocean;
        worldGrid.allTiles[num].temperature = 0f;
        worldGrid.allTiles[num].rainfall = 0f;
        worldGrid.allTiles[num].pathCostCalculated = new int[Find.WorldReachability.NumWorldObjects];
        worldGrid.allTiles[num].waterCovered = true;
        worldGrid.allTiles[num].potentialRoads = new int[2];
        worldGrid.allTiles[num].potentialRivers = new int[2];
        worldGrid.allTiles[num].rivers = new List<int>();
        worldGrid.allTiles[num].neighbors = new Tile[9];
        worldGrid.allTiles[num].neighborID = new int[9];

        for (int k = 0; k < 9; k++) //循环迭代当前瓦块周围的临近瓦块
        {
            worldGrid.allTiles[num].neighborID[k] = -1; //没有邻居，处理边界。
        }

        //如果这个瓦块在边界上，设置entireEdgeTiles这个布尔值为 true。
        if (i == 0 || j == 0 || i == length - 1 || j == height - 1)
        {
            entireEdgeTiles[num] = true;
        }

        //设置当前Tiles数组（平铺瓦片）中的位置值和全局地图ID。
        worldGrid.allTiles[num].id = num;
        worldGrid.allTiles[num].globalID = World.genWorldIDCounter;

        tilesArray[i, j] = num; //记录下每个瓦块的id。
        num++; //计数器自增，进入到下一个瓦块。
    }
}

tilesCount = num; //记录生成的地图瓦块数量。
```

在RimWorld:环世界的源代码中，length和height都是在World类的静态初始化构造函数中计算的。World类是游戏世界的最顶层类，包括整个游戏世界的初始化和渲染等一系列操作。

具体来说，length和height分别对应游戏地图在x轴和y轴上的长度，可以理解为游戏地图的长和宽。在World类的静态初始化构造函数中，会根据生成设置（generation settings）中指定的地图大小和分辨率计算出游戏地图在x轴和y轴上的瓦块（tile）数量，从而得到length和height的值。代码如下所示：

```
public static class WorldGenerator
{
    // ...

    //该方法用于根据生成设置计算游戏地图在x轴和y轴上的瓦块数量（length和height）
    private static void GenerateTileSet(int subCount)
    {
        float num = Find.World.genSettings.mapSize;
        int num2 = Mathf.RoundToInt(Mathf.Sqrt(num * 2.809f) * (float)subCount);
        length = num2 + 1;
        height = num2 + 1;
    }

    // ...
}
```

